var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘 양이 전화를 받지 않는다고요?","JPN":"シエルさんが電話に出ないですって？","ENG":"Ciel's not answering her phone?","TWN":"你說希爾同學都沒接電話嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그럼! 수업에는 나오지 않고 이 관심종자가 전화는 몇 통이나 걸었는데도 받지 않았어.","JPN":"そうよ！　授業にも来なかったし、常に他人に矢印を向けているはずなのに、いくら電話しても出ないの。","ENG":"Yeah! She skipped class, and she won't answer the phone no matter how many times I try calling this attention seeker!","TWN":"對啊！她沒來上課，打了好幾通電話也沒接。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"무단결석에 학생회 임원의 호출 무시. 이 정도면 징계위원회 감이라고 봐도 되겠지?","JPN":"無断欠席に、生徒会役員からの呼び出しも無視。これって懲戒処分が下ってもおかしくないわよね？","ENG":"Skipping class and ignoring the Student Council's calls. Isn't this enough to try her on the disciplinary committee?","TWN":"她無故曠課，又無視學生會幹部的來電，這樣應該要送懲戒委員會吧？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"난 호출한 적 없어. 네가 내 휴대폰을 멋대로 썼을 뿐이잖아.","JPN":"あたしは呼び出しなんかしてないよ。あなたが勝手にあたしの携帯を使ったんでしょ。","ENG":"I never called her. You took my phone and used it without my permission.","TWN":"我又沒有打給她，是你硬拿我的電話打給她的。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…이해했습니다.","JPN":"……状況は理解しました。","ENG":"...Understood.","TWN":"…我明白了。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇다면 지금 시엘 양의 행방을 아는 사람은 아무도 없다는 거군요.","JPN":"つまり今、シエルさんがどこにいるか知っている人は、誰もいないってことですよね。","ENG":"So no one knows Ciel's whereabouts right now.","TWN":"意思就是現在沒有人知道希爾同學的下落是嗎。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어라? 학생회장님이 직접 찾으러 가시게요?","JPN":"あらら？　生徒会長が直接探しに行かれるんですか？","ENG":"Huh? Are you going to go look for her yourself, Ms. President?","TWN":"嗯？學生會長要親自去找人嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네, 저녁은 함께 먹기로 약속했거든요.","JPN":"ええ、今日は一緒に夕飯を食べる約束をしているので。","ENG":"Yes. We made plans to have dinner together.","TWN":"對，我們有約好要一起吃晚餐。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"굳이 찾을 필요도 없어.","JPN":"わざわざ探すまでもないわ。","ENG":"You don't need to go looking for her.","TWN":"不用找啦！"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"또 배가 아프다는 핑계로 화장실에 있거나, 벤치에 널브러져서 낮잠 자고 있겠지.","JPN":"どうせまたお腹痛いとか言ってトイレに閉じこもっているか、ベンチでだらしなく昼寝でもしてるんだから。","ENG":"I figure she's in the restroom with some bogus stomachache or napping on a bench somewhere.","TWN":"我看她不是又假裝肚子痛在廁所混，就是躺在長椅上睡覺吧？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"놀라울 정도로 예전의 나이엘과 비슷하잖아?","JPN":"それ、昔のナイエルちゃんとそっくりだね！","ENG":"That sounds just like the old Naielle.","TWN":"這不就是以前的奈爾嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"시끄러! 안 그러거든?! 요즘은.","JPN":"うるさいわよ！　最近は真面目にやってるじゃない！","ENG":"Shut it! I don't do that! Well, not anymore, at least!","TWN":"你閉嘴！我才沒有？！最近啦！"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응! 시엘에게 라이벌 의식을 갖고 뭐든 열심히 하려는 나이엘의 모습! 보기 좋더라!","JPN":"うん！　シエルちゃんにライバル意識を持ってから何でも頑張って取り組むようになったナイエルちゃんは、とても素敵だよ！","ENG":"Yup! It's really nice to see you work hard with Ciel being your rival and all!","TWN":"嗯！你最近很努力，因為你不想輸給你的假想敵希爾！"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"우, 웃기시네! 누가 그런 열등생을 라이벌로 생각한다는 거야!","JPN":"ふ、ふざけないで！　あんな劣等性、ライバルでもなんでもないわよ！","ENG":"A-as if! Who'd think of a loser like that as a rival?!","TWN":"笑，笑死人！誰把那個劣等生當成假想敵啦！"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"나이엘 양.","JPN":"ナイエルさん。","ENG":"Naielle.","TWN":"奈爾同學。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘 양이 우리 아카데미에 온 목적을 기억하고 있나요?","JPN":"シエルさんがこのアカデミーに来た目的、覚えていますか？","ENG":"Do you remember for what purpose Ciel enrolled in the Academy?","TWN":"你們還記得希爾同學來學院的目的嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"아카데미에 온 목적…? 그야 무슨 고향의 전통 때문에 자길 이긴 상대랑 결혼을 한다고…","JPN":"アカデミーに来た目的……？　故郷のしたきりがあって、それで自分に勝利した相手と結婚するとかって……","ENG":"Her purpose...? It was, something about finding a suitable marriage partner...?","TWN":"來學院的目的…？不就是什麼按照老家的傳統要跟打贏自己的人結婚嗎…"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"결혼을…?","JPN":"結婚……？","ENG":"Marriage...?","TWN":"結婚…？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};